function Avatar({nome, cor, size=42, idx=0, style={}}) {
  const bg = AVATAR_BG[idx % AVATAR_BG.length](cor);
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 40 40" width="${size}" height="${size}"><rect width="40" height="40" rx="${size*.28}" fill="${cor}18"/>${bg}</svg>`;
  return (
    <div style={{width:size,height:size,borderRadius:size*.28,overflow:"hidden",flexShrink:0,position:"relative",display:"flex",alignItems:"center",justifyContent:"center",...style}}>
      <div dangerouslySetInnerHTML={{__html:svg}} style={{position:"absolute",inset:0}}/>
      <span style={{position:"relative",zIndex:1,fontWeight:800,fontSize:size*.34,color:"#fff",letterSpacing:-0.5,textShadow:`0 1px 4px rgba(0,0,0,.5)`}}>{ini(nome)}</span>
    </div>
  );
}

// ── Tooltip customizado ───────────────────────────────────────────────────────
const Tip = ({active,payload,label}) => {
  if(!active||!payload?.length) return null;
  return (
    <div style={{background:"#111827",border:"1px solid #374151",borderRadius:10,padding:"10px 14px",boxShadow:"0 8px 32px rgba(0,0,0,.6)"}}>
      <div style={{fontSize:11,color:"#9CA3AF",marginBottom:5,fontWeight:500}}>{label}</div>
      {payload.map((p,i)=>(
        <div key={i} style={{fontSize:15,fontWeight:700,color:p.color||p.stroke||"#7EC742",fontFamily:"DM Mono,monospace"}}>{fmt(p.value)}</div>
      ))}
    </div>
  );
};

// ── AnimCounter ───────────────────────────────────────────────────────────────
function AnimCounter({value, dur=1100}) {
  const [v,setV]=useState(0);
  const raf=useRef();
  useEffect(()=>{
    const t0=Date.now();
    const tick=()=>{
      const p=Math.min((Date.now()-t0)/dur,1);
      const e=1-Math.pow(1-p,3);
      setV(Math.round(value*e));
      if(p<1) raf.current=requestAnimationFrame(tick);
    };
    raf.current=requestAnimationFrame(tick);
    return()=>cancelAnimationFrame(raf.current);
  },[value]);
  return <>{fmt(v)}</>;
}

// ── StatCard ──────────────────────────────────────────────────────────────────
function StatCard({label,icon,value,color,isNum=false,delay=0}) {
  return (
    <div className="card" style={{background:"#111827",border:`1px solid ${color}25`,borderRadius:16,padding:"18px 20px",position:"relative",overflow:"hidden",animation:`fadeUp .5s ease ${delay}s both`}}>
      <div style={{position:"absolute",top:-20,right:-20,width:80,height:80,borderRadius:"50%",background:`radial-gradient(circle,${color}20,transparent 70%)`}}/>
      <div style={{fontSize:22,marginBottom:8}}>{icon}</div>
      <div style={{fontSize:10,color:"#6B7280",textTransform:"uppercase",letterSpacing:2,fontWeight:600,marginBottom:5}}>{label}</div>
      <div style={{fontSize:22,fontWeight:800,color,fontFamily:"DM Mono,monospace",lineHeight:1.1}}>
        {isNum ? <AnimCounter value={value}/> : value}
      </div>
    </div>
  );
}

